namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) });
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) });
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "New feature: dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-2) });
    }

    public List<NotificationItem> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<NotificationItem> GetNotificationsSince(int lastId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called by a background hosted service.
    /// </summary>
    public void GenerateFakeNotification()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready to download.",
            "A comment was added to your thread.",
            "Weekly summary is available.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow
            });
        }
    }
}

namespace BlazorApp.Services;

/// <summary>
/// Background service that periodically generates fake notifications
/// so there is new data for the polling page to discover.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notificationService;

    public NotificationGeneratorService(NotificationService notificationService)
    {
        _notificationService = notificationService;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
            _notificationService.GenerateFakeNotification();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var item in notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @item.Message
                <small class="text-muted">@item.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorApp.Services.NotificationItem> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR (and also during interactive init).
        // This ensures they appear in the server-rendered HTML.
        notifications = NotificationService.GetNotifications();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires in interactive mode, not during static SSR prerender.
            // This is the safe place to start the polling loop.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var newItems = NotificationService.GetNotificationsSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

